```class Solution {
public:
    int numMusicPlaylists(int n, int goal, int k) {
        const int MOD = 1e9 + 7;
        vector<vector<long long>> dp(n + 1, vector<long long>(goal + 1, 0));
        dp[0][0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= goal; j++) {
                dp[i][j] = (dp[i - 1][j - 1] * i) % MOD;
                if (j > k) {
                    dp[i][j] = (dp[i][j] + dp[i][j - 1] * (i - k)) % MOD;
                }
            }
        }
        return dp[n][goal];
    }
};
